        for i := n-3; i >= 0; i-- {
            if base[i] > suffixMax[i+1] {
                suffixMax[i] = base[i]
            } else {
                suffixMax[i] = suffixMax[i+1]
            }
        }
    }

    for i := 0; i < n; i++ {
        cand1 := 0
        if i >= 2 {
            cand1 = prefixMax[i-2]
        }

        cand2 := 0
        if i >= 1 && i <= n-2 {
            cand2 = commonPrefixLength(words[i-1], words[i+1])
